CREATE TABLE public."Voice-Bot-1" (id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY, content_text TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT now()); GRANT SELECT, INSERT, UPDATE, DELETE ON public."Voice-Bot-1" TO authenticated; GRANT ALL ON public."Voice-Bot-1" TO service_role; ALTER TABLE public."Voice-Bot-1" ENABLE ROW LEVEL SECURITY; CREATE POLICY "Service role manages voice bot context" ON public."Voice-Bot-1" FOR ALL TO service_role USING (true) WITH CHECK (true);